  { name: "Liu Shan", roles: [Role.ROAM] },
  { name: "Sun Bin", roles: [Role.ROAM, Role.MID] },
  { name: "Guiguzi", roles: [Role.ROAM] },
  { name: "Taiyi", roles: [Role.ROAM] },
