import { ROLES_ORDER } from '../constants';

const BRACKET_NAMES = [
  "Alpha", "Beta", "Charlie", "Delta", "Echo", "Foxtrot", 
  "Golf", "Hotel", "India", "Juliet", "Kilo", "Lima",
  "Mike", "November", "Oscar", "Papa"
];

const BRACKET_COLORS = [
  "#00d2ff", // Cyan
  "#ef4444", // Red
  "#fbbf24", // Gold
  "#a855f7", // Purple
  "#10b981", // Emerald
  "#f97316", // Orange
  "#ec4899", // Pink
  "#ffffff", // White
