             ...prev,
             teams: prev.teams.map(team => ({
                 ...team,
                 slots: team.slots.map(slot => slot.player.id === updatedPlayer.id ? { ...slot, player: { ...slot.player, name: updatedPlayer.name } } : slot)
             }))
