                                <div className="flex gap-1">{[3, 4, 5, 6, 8, 12].map(n => (<button key={n} onClick={() => setNumBracketTeams(n)} className={`flex-1 py-2 font-orbitron font-bold text-xs clip-corner-sm border transition-all ${numBracketTeams === n ? 'bg-[#dcb06b] text-black border-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-black/40 text-[#4a5f78] border-[#1e3a5f]'}`}>{n}</button>))}</div>
