                     <Button variant="secondary" onClick={() => setSetupStep(prev => (prev - 1) as 1|2|3)} className="w-32 border-[#1e3a5f] text-[#4a5f78] hover:text-white">BACK</Button>
                 ) : (
                     <div className="w-32"></div>
